using Microsoft.ML;
using Microsoft.ML.Data;

var builder = WebApplication.CreateBuilder(args);
var app = builder.Build();

// ── ML.NET setup ───────────────────────────────────────────────────────
var mlContext = new MLContext(seed: 42);
var dataPath = Path.Combine(AppContext.BaseDirectory, "Data", "customers.csv");

// Load data
IDataView allData = mlContext.Data.LoadFromTextFile<CustomerData>(
    dataPath, hasHeader: true, separatorChar: ',');

// Split 80/20
var split = mlContext.Data.TrainTestSplit(allData, testFraction: 0.2);

// Build pipeline: encode Region, combine features, train with SDCA
var pipeline = mlContext.Transforms.Categorical
        .OneHotEncoding("RegionEncoded", nameof(CustomerData.Region))
    .Append(mlContext.Transforms.Concatenate("Features",
        nameof(CustomerData.Age),
        nameof(CustomerData.Income),
        nameof(CustomerData.PurchaseHistory),
        "RegionEncoded"))
    .Append(mlContext.Transforms.NormalizeMinMax("Features"))
    .Append(mlContext.BinaryClassification.Trainers.SdcaLogisticRegression(
        labelColumnName: "Label", featureColumnName: "Features"));

// Train
var model = pipeline.Fit(split.TrainSet);

// Evaluate
var metrics = mlContext.BinaryClassification.Evaluate(
    model.Transform(split.TestSet), labelColumnName: "Label");

Console.WriteLine($"Accuracy: {metrics.Accuracy:P2}  |  AUC: {metrics.AreaUnderRocCurve:P2}  |  F1: {metrics.F1Score:P2}");

// Create prediction engine
var predEngine = mlContext.Model
    .CreatePredictionEngine<CustomerData, ChurnPrediction>(model);

// ── Endpoints ──────────────────────────────────────────────────────────
app.MapGet("/", () => new
{
    accuracy = metrics.Accuracy,
    auc = metrics.AreaUnderRocCurve,
    f1 = metrics.F1Score
});

app.MapPost("/predict", (CustomerInput input) =>
{
    var data = new CustomerData
    {
        Age = input.Age,
        Income = input.Income,
        Region = input.Region,
        PurchaseHistory = input.PurchaseHistory
    };
    var result = predEngine.Predict(data);
    return new
    {
        willChurn = result.PredictedLabel,
        probability = result.Probability,
        score = result.Score
    };
});

app.Run();

// ── Data models ────────────────────────────────────────────────────────

public class CustomerData
{
    [LoadColumn(0)] public float Age { get; set; }
    [LoadColumn(1)] public float Income { get; set; }
    [LoadColumn(2)] public string Region { get; set; } = "";
    [LoadColumn(3)] public float PurchaseHistory { get; set; }
    [LoadColumn(4), ColumnName("Label")]
    public bool Churned { get; set; }
}

public class CustomerInput
{
    public float Age { get; set; }
    public float Income { get; set; }
    public string Region { get; set; } = "";
    public float PurchaseHistory { get; set; }
}

public class ChurnPrediction
{
    [ColumnName("PredictedLabel")]
    public bool PredictedLabel { get; set; }
    public float Probability { get; set; }
    public float Score { get; set; }
}

